    budgetLabel: '\u0411\u044E\u0434\u0436\u0435\u0442 \u043D\u0430 \u0440\u0435\u0441\u0442\u0430\u0432\u0440\u0430\u0446\u0438\u044E:',
    budgetLabelAm: '\u054E\u0565\u0580\u0561\u056F\u0561\u0576\u0563\u0576\u0574\u0561\u0576 \u0562\u0575\u0578\u0582\u057B\u0565\u055D',
    budgetLabelEn: 'Restoration budget:',
