    buttonLabelEn: 'Become a Sponsor',
    address: '\u043C\u0435\u0442\u0440\u043E \u041F\u043B\u043E\u0449\u0430\u0434\u044C \u0420\u0435\u0441\u043F\u0443\u0431\u043B\u0438\u043A\u0438',
    addressAm: '\u0540\u0561\u0576\u0580\u0561\u057A\u0565\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0580\u0561\u057A\u0561\u0580\u0561\u056F\u056B \u0574\u0565\u057F\u0580\u0578',
